#include <stdio.h>
#define MOD 1000000007
int dp[1001][301][10];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int R, B, L;
        scanf("%d %d %d", &R, &B, &L);
        for (int i = 0; i <= R; i++) {
            for (int j = 0; j <= B; j++) {
                for (int k = 0; k <= L; k++) {
                    dp[i][j][k] = 0;
                }
            }
        }
        dp[0][0][0] = 1;
        for (int i = 0; i <= R; i++) {
            for (int j = 1; j <= B; j++) {
                for (int k = 0; k <= L; k++) {
                    if (i >= 4) dp[i][j][k] = (dp[i][j][k] + dp[i - 4][j - 1][k]) % MOD;
                    if (i >= 6) dp[i][j][k] = (dp[i][j][k] + dp[i - 6][j - 1][k]) % MOD;
                    dp[i][j][k] = (dp[i][j][k] + dp[i][j - 1][k]) % MOD;
                    if (k < L) dp[i][j][k] = (dp[i][j][k] + dp[i][j - 1][k + 1]) % MOD;
                }
            }
        }
        printf("%d\n", dp[R][B][L]);
    }
    return 0;
}

